INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f15bdce0-31f8-4273-9337-72804f4b7dbe',
  '00000000-0000-0000-0000-000000000001',
  $escape$Express Routing — Parameters, Grouping, and Router.use() Prefixing$escape$,
  $escape$Express routes are defined on the app object or a Router instance using HTTP-method functions: app.get(), app.post(), app.put(), app.delete(). Route parameters are prefixed with a colon and accessed via req.params — /users/:id makes req.params.id available. Optional parameters use a trailing ?: /files/:name?. For wildcard segments use *: /api/* catches all paths under /api.

Grouping and prefixing is done with express.Router(). Create a router module, hang routes on it, then mount it on the main app with app.use('/prefix', router). This keeps related routes collocated and the prefix is applied once at mount time — changing /api/v1 to /api/v2 is a single-line update. Routers also accept their own middleware via router.use(), scoping it to only that sub-tree. For deeply nested resources, stack multiple Router instances: app.use('/users', usersRouter) where usersRouter itself does router.use('/:userId/posts', postsRouter).$escape$,
  $escape$import express from 'express';

const app = express();
const usersRouter = express.Router();
const postsRouter = express.Router({ mergeParams: true });

// Route parameter
usersRouter.get('/:userId', (req, res) => {
  res.json({ userId: req.params.userId });
});

// Nested router — mergeParams exposes :userId here
postsRouter.get('/', (req, res) => {
  res.json({ userId: req.params.userId, posts: [] });
});

usersRouter.use('/:userId/posts', postsRouter);
app.use('/api/v1/users', usersRouter);

app.listen(3000);$escape$,
