INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '16e84155-d648-498b-8990-64b65734760a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Express API Versioning — URI Strategy, Router Isolation, and OpenAPI Generation$escape$,
  $escape$Versioning Express APIs via URI prefixes (`/api/v1/`) is the most explicit approach — clients see the contract they're bound to. The key is isolating each version into its own `express.Router()`, then mounting it on the app. This prevents v1 handlers from bleeding into v2 and lets you deprecate cleanly.

For OpenAPI generation, `swagger-jsdoc` parses JSDoc comments above route handlers and produces a spec at runtime. Mount `swagger-ui-express` on `/api/docs` and pass it the generated spec — no separate YAML file to maintain. Pair this with `zod-to-openapi` or `express-zod-api` if you're already using Zod for request validation; your schema becomes both your runtime guard and your documentation source.

Version your routers in separate files (`routes/v1/users.ts`, `routes/v2/users.ts`), export them, and mount conditionally. When v2 is stable, deprecate v1 by injecting a `Deprecation` response header via a per-router middleware rather than removing the routes immediately — gives clients time to migrate without silent breakage.$escape$,
  $escape$import express from 'express';
import swaggerJsdoc from 'swagger-jsdoc';
import swaggerUi from 'swagger-ui-express';
import v1Router from './routes/v1';
import v2Router from './routes/v2';

const app = express();

const deprecationMiddleware: express.RequestHandler = (_req, res, next) => {
  res.setHeader('Deprecation', 'version="v1"');
  res.setHeader('Sunset', 'Sat, 01 Jan 2026 00:00:00 GMT');
  next();
};

app.use('/api/v1', deprecationMiddleware, v1Router);
app.use('/api/v2', v2Router);

const spec = swaggerJsdoc({
  definition: { openapi: '3.0.0', info: { title: 'ByteAI API', version: '2.0.0' } },
  apis: ['./routes/**/*.ts'],
});
app.use('/api/docs', swaggerUi.serve, swaggerUi.setup(spec));$escape$,
  $escape$typescript$escape$,
