INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fc08d7ee-2dc9-4930-a9ef-44e524c00613',
  '00000000-0000-0000-0000-000000000001',
  $escape$Express Serialization — DTOs, camelCase vs snake_case, and Null Handling$escape$,
  $escape$Express gives you zero serialization opinions out of the box — `res.json()` calls `JSON.stringify()` and moves on. That means DTO shaping, case conventions, and null hygiene are entirely your responsibility.

For camelCase responses from a snake_case database, don't manually rename fields on every route. Instead, install `humps` and wrap `res.json` in a global middleware that runs `camelizeKeys()` on every outgoing payload. This keeps your route handlers clean and consistent.

For null handling, Express won't strip `undefined` values but will serialize `null` as `null`. If you want to omit undefined fields from responses, configure your serializer explicitly — or use a DTO class with `JSON.stringify` replacer logic.

Request DTOs are equally critical: use `zod` to parse and strip unknown fields from `req.body` before they touch your business logic. A `z.object().strict()` schema rejects unexpected keys and gives you a typed, sanitized object — no accidental passthrough of client-supplied garbage.$escape$,
  $escape$import express from 'express';
import { camelizeKeys } from 'humps';
import { z } from 'zod';

const app = express();
app.use(express.json());

// Global camelCase serializer
app.use((_req, res, next) => {
  const originalJson = res.json.bind(res);
  res.json = (body) => originalJson(camelizeKeys(body));
  next();
});

const CreateUserDTO = z.object({
  email: z.string().email(),
  display_name: z.string().min(1),
}).strict();

app.post('/users', (req, res) => {
  const parsed = CreateUserDTO.safeParse(req.body);
  if (!parsed.success) return res.status(400).json({ errors: parsed.error.flatten() });
  // parsed.data is clean and typed
  res.status(201).json({ user_id: 42, display_name: parsed.data.display_name });
});$escape$,
  $escape$javascript$escape$,
